def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    for c in range(1, b + 3):
                        factor = ((ratio - a) ** 6) / ((a + b + c) * 1.1 + 1)
                        priority += factor * np.cos(ratio * b / (c + 1)) * np.sin(ratio * c / (a + 2))
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.3) * np.cos(ratio * 0.7)) ** 1.7
        elif 4 < ratio <= 7:
            for d in range(1, int(np.ceil(ratio)) + 5):
                for e in range(1, d + 3):
                    term1 = ((ratio - d) ** 4) * np.sin(ratio * d) / (e + 0.7)
                    term2 = np.tanh(term1) * 1.5
                    priority += term2 + np.cos(ratio * e) * 0.3
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4) * 3
        elif 2 <= ratio <= 4:
            s = 0
            for f in range(1, 14):
                power = ((ratio - 2) ** f) / (f * 2.0)
                s += power * np.cos(f * ratio) * np.sin(3 * f * ratio)
            priority = (s * np.cos(8 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 2
            if bin_cap < item * 2:
                priority += np.exp(-(ratio-2)**2) * 4
            else:
                priority -= np.sqrt(bin_cap / (item+0.1)) * 2.5
        elif 1 <= ratio < 2:
            s = 0
            for g in range(1, 12):
                s += ((2 - ratio) ** g) / (g ** 2 + 1.0) * np.sin(g * 15 * ratio)
            penalty = 0
            if bin_cap < item * 1.3:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(30 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for h in range(1, 6):
                priority += np.sin(h * ratio * i) * ((ratio - 1) ** h) / h * 0.9
        elif 0.5 <= ratio < 1:
            s = 0
            for j in range(1, 18):
                s += ((1 - ratio) ** j) / (j * 3.5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.6
            else:
                priority /= (np.sqrt(bin_cap + 2.5) + 3)
            for k in range(1, 8):
                priority += ((1 - ratio) ** k) * np.sin(k * item * 2.0) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for l in range(1, 15):
                s += ((0.5 - ratio) ** l) / (l * 5) * np.cos(l * ratio * 3)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 2.5) % 6 == 0:
                priority *= 3
            else:
                priority /= 3.5
            if bin_cap < item * 0.35:
                priority += np.log1p(item * bin_cap * 1.5) * 5
            else:
                priority -= np.exp(-ratio * 2.5) * 4.5
            for m in range(1, 10):
                priority += ((0.5 - ratio) ** m) / (m * 9) * np.cos(item * m * 1.5)
        else:
            s = 0
            for n in range(1, 12):
                s += ((0.2 - ratio) ** n) / (n * 6) * np.sin(n * item * 1.2) * np.cos(n * ratio * 0.5)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 1.1) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap * 2) * 6
            else:
                priority -= np.exp(-ratio * 2.8) * 5
            for o in range(1, 10):
                priority += ((0.2 - ratio) ** o) / (o * 8) * np.cos(item * o * 0.9)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
